1	<script>
2		// Turn the probe until the meter agrees.
3		// probeAngle: primary slider value, degrees, 0..360, step 5.
4		// lengthC1: named auxiliary control, relative length of candidate c1, 0.5..2, step 0.1.
5		let probeAngle = $state(40);
6		let lengthC1 = $state(1);
7	
8		let diagramEl = $state(null);
9	
10		// viewBox is deliberately wider than tall: candidates only ever fan through
11		// the upper half of the circle, so the canvas is cropped to that content
12		// instead of wasting a full square of empty space above the score bars.
13		const VIEW_W = 320;
14		const VIEW_H = 230;
15		const CENTER_X = 160;
16		const CENTER_Y = 150;
17		const R = 50;
18		const MAX_SCORE = 2;
19	
20		const baseCandidates = [
21			{ name: 'c1', angle: 20 },
22			{ name: 'c2', angle: 70 },
23			{ name: 'c3', angle: 110 },
24			{ name: 'c4', angle: 160 }
25		];
26	
27		function computeHead(tipX, tipY, dirX, dirY, shaftLen) {
28			const headLen = shaftLen * 0.18;
29			const halfW = shaftLen * 0.09;
30			const backX = tipX - dirX * headLen;
31			const backY = tipY - dirY * headLen;
32			const perpX = -dirY;
33			const perpY = dirX;
34			const lx = backX + perpX * halfW;
35			const ly = backY + perpY * halfW;
36			const rx = backX - perpX * halfW;
37			const ry = backY - perpY * halfW;
38			return { backX, backY, poly: `${tipX},${tipY} ${lx},${ly} ${rx},${ry}` };
39		}
40	
41		let candidateData = $derived.by(() => {
42			return baseCandidates.map((c) => {
43				const len = c.name === 'c1' ? lengthC1 : 1;
44				const rad = (c.angle * Math.PI) / 180;
45				const dirX = Math.cos(rad);
46				const dirY = -Math.sin(rad);
47				const shaft = R * len;
48				const tipX = CENTER_X + dirX * shaft;
49				const tipY = CENTER_Y + dirY * shaft;
50				const head = computeHead(tipX, tipY, dirX, dirY, shaft);
51				// label offset is measured from the TIP, not from the center, so it
52				// stays a fixed safe distance from the length handle no matter how
53				// long or short c1 gets.
54				const labelR = shaft + 36;
55				const labelX = CENTER_X + dirX * labelR;
56				const labelY = CENTER_Y + dirY * labelR;
57				const diff = ((probeAngle - c.angle) * Math.PI) / 180;
58				const score = Math.cos(diff) * len;
59				return { ...c, len, tipX, tipY, ...head, labelX, labelY, score };
60			});
61		});
62	
63		let probeGeom = $derived.by(() => {
64			const rad = (probeAngle * Math.PI) / 180;
65			const dirX = Math.cos(rad);
66			const dirY = -Math.sin(rad);
67			const shaft = R;
68			const tipX = CENTER_X + dirX * shaft;
69			const tipY = CENTER_Y + dirY * shaft;
70			const head = computeHead(tipX, tipY, dirX, dirY, shaft);
71			const perpX = -dirY;
72			const perpY = dirX;
73			// Pushed well clear of the 44px handle hit box (radial + tangential
74			// combined) so the label never sits under the probe dot or its focus
75			// ring at any angle. The radial reach is deliberately well beyond any
76			// candidate label's radius (even c1 stretched to its own labels'
77			// range) and the tangential kick is large enough that even when the
78			// probe sits exactly on top of a candidate's line (e.g. 70 degrees on
79			// c2), the two label centers land 40+ px apart, never abutting.
80			const labelX = CENTER_X + dirX * (R + 56) + perpX * 38;
81			const labelY = CENTER_Y + dirY * (R + 56) + perpY * 38;
82			return { tipX, tipY, ...head, labelX, labelY };
83		});
84	
85		let probeHandlePos = $derived.by(() => ({
86			x: (probeGeom.tipX / VIEW_W) * 100,
87			y: (probeGeom.tipY / VIEW_H) * 100
88		}));
89	
90		let c1HandlePos = $derived.by(() => {
91			const c1 = candidateData.find((c) => c.name === 'c1');
92			return { x: (c1.tipX / VIEW_W) * 100, y: (c1.tipY / VIEW_H) * 100 };
93		});
94	
95		function roundScore(s) {
96			let v = Math.round(s * 10) / 10;
97			if (Object.is(v, -0)) v = 0;
98			return v;
99		}
100	
101		// A leader is only crowned when its rounded, displayed score strictly
102		// beats every other rounded score. If two or more candidates share the
103		// top rounded value the emphasis is suppressed entirely (no false bold).
104		let leaderName = $derived.by(() => {
105			const rounded = candidateData.map((c) => roundScore(c.score));
106			const max = Math.max(...rounded);
107			const tiedCount = rounded.filter((r) => r === max).length;
108			if (tiedCount > 1) return null;
109			const idx = rounded.indexOf(max);
110			return candidateData[idx].name;
111		});
112	
113		function updateProbeFromEvent(e) {
114			if (!diagramEl) return;
115			const rect = diagramEl.getBoundingClientRect();
116			const scaleX = VIEW_W / rect.width;
117			const scaleY = VIEW_H / rect.height;
118			const lx = (e.clientX - rect.left) * scaleX;
119			const ly = (e.clientY - rect.top) * scaleY;
120			const dx = lx - CENTER_X;
121			const dy = ly - CENTER_Y;
122			let deg = (Math.atan2(-dy, dx) * 180) / Math.PI;
123			if (deg < 0) deg += 360;
124			if (deg > 360) deg = 360;
125			probeAngle = deg;
126		}
127	
128		function onProbePointerDown(e) {
129			e.preventDefault();
130			e.currentTarget.setPointerCapture(e.pointerId);
131			updateProbeFromEvent(e);
132			const move = (ev) => updateProbeFromEvent(ev);
133			const up = () => {
134				window.removeEventListener('pointermove', move);
135				window.removeEventListener('pointerup', up);
136			};
137			window.addEventListener('pointermove', move);
138			window.addEventListener('pointerup', up);
139		}
140	
141		function onProbeKeydown(e) {
142			let handled = true;
143			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = Math.min(360, probeAngle + 5);
144			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = Math.max(0, probeAngle - 5);
145			else if (e.key === 'Home') probeAngle = 0;
146			else if (e.key === 'End') probeAngle = 360;
147			else handled = false;
148			if (handled) e.preventDefault();
149		}
150	
151		function updateLengthFromEvent(e) {
152			if (!diagramEl) return;
153			const rect = diagramEl.getBoundingClientRect();
154			const scaleX = VIEW_W / rect.width;
155			const scaleY = VIEW_H / rect.height;
156			const lx = (e.clientX - rect.left) * scaleX;
157			const ly = (e.clientY - rect.top) * scaleY;
158			const dx = lx - CENTER_X;
159			const dy = ly - CENTER_Y;
160			const dist = Math.sqrt(dx * dx + dy * dy);
161			let len = dist / R;
162			len = Math.min(2, Math.max(0.5, len));
163			lengthC1 = Math.round(len * 10) / 10;
164		}
165	
166		function onLengthPointerDown(e) {
167			e.preventDefault();
168			e.currentTarget.setPointerCapture(e.pointerId);
169			updateLengthFromEvent(e);
170			const move = (ev) => updateLengthFromEvent(ev);
171			const up = () => {
172				window.removeEventListener('pointermove', move);
173				window.removeEventListener('pointerup', up);
174			};
175			window.addEventListener('pointermove', move);
176			window.addEventListener('pointerup', up);
177		}
178	
179		function onLengthKeydown(e) {
180			let handled = true;
181			if (e.key === 'ArrowRight' || e.key === 'ArrowUp')
182				lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
183			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown')
184				lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
185			else if (e.key === 'Home') lengthC1 = 0.5;
186			else if (e.key === 'End') lengthC1 = 2;
187			else handled = false;
188			if (handled) e.preventDefault();
189		}
190	</script>
191	
192	<div class="wrap" data-interactive="dot-alignment">
193		<p class="instruction">Drag the probe to score each candidate. Drag c1's handle to change its length.</p>
194	
195		<div class="diagram-wrap" bind:this={diagramEl}>
196			<svg
197				viewBox="0 0 {VIEW_W} {VIEW_H}"
198				class="diagram-svg"
199				role="img"
200				aria-label="Diagram: an amber probe arrow rotates among four periwinkle candidate arrows, c1 through c4"
201			>
202				{#each candidateData as c (c.name)}
203					<line
204						x1={CENTER_X}
205						y1={CENTER_Y}
206						x2={c.backX}
207						y2={c.backY}
208						stroke="var(--data-observed)"
209						stroke-width="2.2"
210						stroke-linecap="round"
211					/>
212					<polygon points={c.poly} fill="var(--data-observed)" />
213					<text
214						x={c.labelX}
215						y={c.labelY}
216						class="arrow-label"
217						text-anchor="middle"
218						dominant-baseline="middle"
219						aria-hidden="true"
220					>
221						{c.name}
222					</text>
223				{/each}
224	
225				<line
226					x1={CENTER_X}
227					y1={CENTER_Y}
228					x2={probeGeom.backX}
229					y2={probeGeom.backY}
230					stroke="var(--data-heat)"
231					stroke-width="2.2"
232					stroke-linecap="round"
233					class="probe-line"
234				/>
235				<polygon points={probeGeom.poly} fill="var(--data-heat)" />
236				<text
237					x={probeGeom.labelX}
238					y={probeGeom.labelY}
239					class="arrow-label probe-label"
240					text-anchor="middle"
241					dominant-baseline="middle"
242					aria-hidden="true"
243				>
244					probe
245				</text>
246			</svg>
247	
248			<div
249				class="handle probe-handle"
250				style="left: {probeHandlePos.x}%; top: {probeHandlePos.y}%; --handle-color: var(--data-heat);"
251				role="slider"
252				tabindex="0"
253				aria-label="probe angle in degrees"
254				aria-valuemin="0"
255				aria-valuemax="360"
256				aria-valuenow={Math.round(probeAngle)}
257				onpointerdown={onProbePointerDown}
258				onkeydown={onProbeKeydown}
259			></div>
260	
261			<div
262				class="handle length-handle"
263				style="left: {c1HandlePos.x}%; top: {c1HandlePos.y}%; --handle-color: var(--data-observed);"
264				data-control="length-c1"
265				role="spinbutton"
266				tabindex="0"
267				aria-label="c1 length"
268				aria-valuemin="0.5"
269				aria-valuemax="2"
270				aria-valuenow={lengthC1.toFixed(1)}
271				onpointerdown={onLengthPointerDown}
272				onkeydown={onLengthKeydown}
273			></div>
274		</div>
275	
276		<div class="bars">
277			{#each candidateData as c (c.name)}
278				{@const displayScore = roundScore(c.score).toFixed(1)}
279				<div class="bar-col">
280					<div class="bar-track">
281						<div class="bar-zero"></div>
282						<div
283							class="bar-fill"
284							class:leading={c.name === leaderName}
285							style="height: {Math.min(Math.abs(c.score) / MAX_SCORE, 1) * 40}px; {c.score >= 0
286								? 'bottom: 50%;'
287								: 'top: 50%;'}"
288						></div>
289					</div>
290					<span class="readout" class:leading={c.name === leaderName} aria-label="{c.name} score {displayScore}"
291						>{displayScore}</span
292					>
293					<span class="cand-label">{c.name}</span>
294				</div>
295			{/each}
296		</div>
297	</div>
298	
299	<style>
300		.wrap {
301			display: flex;
302			flex-direction: column;
303			align-items: center;
304			gap: 0.65rem;
305			width: 100%;
306			max-width: 520px;
307			margin: 0 auto;
308			padding: 1rem;
309			box-sizing: border-box;
310		}
311	
312		.instruction {
313			font-family: var(--font-body);
314			color: var(--color-text);
315			font-size: 0.9rem;
316			opacity: 0.85;
317			text-align: center;
318			margin: 0;
319		}
320	
321		.diagram-wrap {
322			position: relative;
323			width: 100%;
324			max-width: 400px;
325			aspect-ratio: 320 / 230;
326		}
327	
328		.diagram-svg {
329			width: 100%;
330			height: 100%;
331			display: block;
332		}
333	
334		.arrow-label {
335			font-family: var(--font-mono);
336			fill: var(--color-text);
337			font-size: 13px;
338			pointer-events: none;
339			user-select: none;
340		}
341	
342		.probe-label {
343			font-size: 13px;
344		}
345	
346		.handle {
347			position: absolute;
348			width: 46px;
349			height: 46px;
350			transform: translate(-50%, -50%);
351			display: flex;
352			align-items: center;
353			justify-content: center;
354			touch-action: none;
355			cursor: grab;
356			background: transparent;
357			border: none;
358			padding: 0;
359		}
360	
361		.handle::before {
362			content: '';
363			width: 14px;
364			height: 14px;
365			border-radius: 50%;
366			background: var(--handle-color);
367			box-shadow: 0 0 0 3px var(--color-bg);
368		}
369	
370		.handle:focus-visible::before {
371			box-shadow: 0 0 0 3px var(--color-bg), 0 0 0 5px var(--handle-color);
372		}
373	
374		.bars {
375			display: flex;
376			justify-content: center;
377			gap: 1.25rem;
378			width: 100%;
379			flex-wrap: wrap;
380			margin-top: -0.25rem;
381		}
382	
383		.bar-col {
384			display: flex;
385			flex-direction: column;
386			align-items: center;
387			gap: 0.25rem;
388			min-width: 60px;
389		}
390	
391		.bar-track {
392			position: relative;
393			width: 26px;
394			height: 80px;
395		}
396	
397		.bar-zero {
398			position: absolute;
399			left: 0;
400			right: 0;
401			top: 50%;
402			height: 1px;
403			background: var(--color-text);
404			opacity: 0.3;
405		}
406	
407		.bar-fill {
408			position: absolute;
409			left: 0;
410			right: 0;
411			background: var(--data-params);
412			opacity: 0.55;
413			transition: height 150ms ease-out, top 150ms ease-out, bottom 150ms ease-out;
414		}
415	
416		.bar-fill.leading {
417			opacity: 1;
418		}
419	
420		.readout {
421			font-family: var(--font-mono);
422			color: var(--data-params);
423			font-size: 0.8rem;
424			opacity: 0.7;
425		}
426	
427		.readout.leading {
428			opacity: 1;
429			font-weight: 700;
430		}
431	
432		.cand-label {
433			font-family: var(--font-mono);
434			color: var(--color-text);
435			font-size: 0.75rem;
436			opacity: 0.75;
437		}
438	
439		@media (prefers-reduced-motion: reduce) {
440			.bar-fill {
441				transition: none;
442			}
443		}
444	</style>
